import{c as r,Q as a,j as e,m as o}from"./chunks/framework.rlpw0eGz.js";const p=JSON.parse('{"title":"搜索提供方","description":"","frontmatter":{},"headers":[],"relativePath":"zh/getting-started/search-provider.md","filePath":"zh/getting-started/search-provider.md","lastUpdated":1777012567000}'),n={name:"zh/getting-started/search-provider.md"};function d(s,t,i,l,h,g){return a(),e("div",null,[...t[0]||(t[0]=[o('<h1 id="搜索提供方" tabindex="-1">搜索提供方 <a class="header-anchor" href="#搜索提供方" aria-label="Permalink to &quot;搜索提供方&quot;">​</a></h1><p>给机器人接 <strong>Search Provider</strong> 后，它能在对话里<strong>实时</strong>查网，用搜索引擎 API 当工具。</p><h2 id="在做什么" tabindex="-1">在做什么 <a class="header-anchor" href="#在做什么" aria-label="Permalink to &quot;在做什么&quot;">​</a></h2><p>每个 Search Provider 是某一家的搜索 API（如 Brave、Google）。配好并绑到机器人后，需要新鲜事实时由模型去调。</p><hr><h2 id="支持哪些" tabindex="-1">支持哪些 <a class="header-anchor" href="#支持哪些" aria-label="Permalink to &quot;支持哪些&quot;">​</a></h2><p>侧栏 <strong>Search Provider</strong> 里建。常见能力包括（以你装的版本为准）：</p><table tabindex="0"><thead><tr><th>引擎</th><th>说明</th></tr></thead><tbody><tr><td><strong>Brave</strong></td><td>隐私和速度常被提及</td></tr><tr><td><strong>Bing</strong></td><td>覆盖面大</td></tr><tr><td><strong>Google</strong></td><td>传统网页搜</td></tr><tr><td><strong>Tavily</strong></td><td>偏 AI 研究向</td></tr><tr><td><strong>SearxNG</strong></td><td>自建聚合</td></tr><tr><td><strong>DuckDuckGo</strong></td><td>偏隐私</td></tr><tr><td>其它</td><td>如搜狗、Serper、Jina、Exa、Bocha、Yandex 等</td></tr></tbody></table><hr><h2 id="建一个" tabindex="-1">建一个 <a class="header-anchor" href="#建一个" aria-label="Permalink to &quot;建一个&quot;">​</a></h2><ol><li>侧栏 <strong>Search Provider</strong>。</li><li><strong>Add Search Provider</strong>。</li><li>填 <strong>Name</strong>、<strong>API Key</strong>，有的引擎还要 <strong>base_url</strong>（如 SearxNG）。</li></ol><p><strong>Edit</strong> 改、<strong>Delete</strong> 删。</p><hr><h2 id="绑到机器人" tabindex="-1">绑到机器人 <a class="header-anchor" href="#绑到机器人" aria-label="Permalink to &quot;绑到机器人&quot;">​</a></h2><ol><li><strong>Bots</strong> → 机器人</li><li><strong>General</strong></li><li><strong>Search Provider</strong> 下拉选中</li><li>保存</li></ol><hr><h2 id="和机器人" tabindex="-1">和机器人 <a class="header-anchor" href="#和机器人" aria-label="Permalink to &quot;和机器人&quot;">​</a></h2><p>需要<strong>较新、较贴问题</strong>的公开信息时，会走搜索，再把结果融进回答；可多结果综合。具体策略由模型和工具设计决定。</p>',18)])])}const _=r(n,[["render",d]]);export{p as __pageData,_ as default};
